// MapComponent.js
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Circle, ZoomControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart";

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://127.0.0.1:8000/buses");
        const data = await response.json();
        setBuses(data);
      } catch (error) {
        console.error("Error fetching buses:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count types
  const normalCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  return (
    <div style={{ position: "relative", width: "100vw", height: "100vh" }}>
      <MapContainer
        center={[40.7128, -74.0060]}
        zoom={12}
        style={{ width: "100%", height: "100%" }}
        zoomControl={false} // disable default zoom control to move it
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        {/* Zoom control on left */}
        <ZoomControl position="topleft" />

        {/* Markers */}
        {buses.map(bus => (
          <Circle
            key={bus.id + "_" + bus.timestamp}
            center={[bus.lat, bus.lon]}
            radius={50}
            color={bus.status === "ghost" ? "red" : bus.status === "anomaly" ? "orange" : "green"}
          />
        ))}
      </MapContainer>

      {/* Toggle Chart Button */}
      <button
        onClick={() => setShowChart(!showChart)}
        style={{
          position: "absolute",
          left: "10px",
          top: "10px",
          zIndex: 1000,
          padding: "8px 12px",
          background: "#fff",
          border: "1px solid #ccc",
          borderRadius: "4px",
          cursor: "pointer"
        }}
      >
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>

      {/* Bus Count Info */}
      <div
        style={{
          position: "absolute",
          left: "10px",
          bottom: "10px",
          zIndex: 1000,
          background: "#fff",
          padding: "8px",
          borderRadius: "4px",
          border: "1px solid #ccc"
        }}
      >
        Normal: {normalCount} | Ghost: {ghostCount} | Anomaly: {anomalyCount}
      </div>

      {/* Chart */}
      {showChart && <BusTrendChart buses={buses} />}
    </div>
  );
};

export default MapComponent;
